declare @message nvarchar(4000)
&CommandQueryVoucherNumber;
if isnull(@stt_rec, '') = '' select @message = @message + ';this._baseCurrencyAmount = this._foreignCurrencyAmount = 0;'
else begin
  declare @pattern varchar(32), @taxCode varchar(32), @taxName nvarchar(511)
  if @@action = 'Edit' select @pattern = ma_tn, @taxCode = ma_thue from @@prime$partition$current where stt_rec = @stt_rec
  else begin
    declare @s nvarchar(4000), @p varchar(6)
    select @p = convert(varchar(6), ngay_ct, 112) from c07$000000 where stt_rec = @stt_rec
    create table #t (c varchar(32), d varchar(32))
    select @s = 'insert into #t select ma_tn, ma_thue from m07$' + @p + ' where stt_rec = ''' + @stt_rec + ''''
    execute sp_executesql @s
    select @pattern = c, @taxCode = d from #t
    drop table #t
  end
  select @taxName = case when @@language = 'V' then ten_thue else ten_thue2 end from tdmthuetp where ma_thue = @taxCode
  select @message = @message + ';this._taxName=''' + replace(replace(isnull(@taxName, ''), '\', '\\'), '''', '\''') + ''''
  if exists (select ma_thue from tdmthuetp where ma_thue = (select ma_thue_tp from tdmtn where ma_tn = @pattern))
    select @message = @message + ';this._baseCurrencyAmount=' + str(a.nguong_thue) + ';this._foreignCurrencyAmount=' + str(a.nguong_thue_nt) + ';'
 	    from dbo.tdmtn a left join dbo.tdmthuetp b on a.ma_thue_tp = b.ma_thue
	    where a.ma_tn = @pattern and a.ma_thue_tp in (select ma_thue from dbo.tdmthuetp)
  else
    select @message = @message + ';this._baseCurrencyAmount = this._foreignCurrencyAmount = 0;'
end
select @message = @message + 'active$Voucher$(this);'
