script.text:
      &ScriptVoucherInit;
      /* <flatten type="Javascript"> */
function init$Voucher$(f) {initialize(f, null, null, null, 'status');}
/* </flatten> */
function active$Voucher$(f) {
  &ScriptActiveVoucher;
  setDefaultValue(f);
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  &ListCreate;
  &PostCreate;
}
function scatter$Voucher$(f) {&ScriptScatterVoucher;setDefaultValue(f);}
function close$Voucher$(f) {
  &ScriptCloseVoucher;
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d07')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    default:
      break;
  }
}
function setDefaultValue(f) {if (f._action == 'New' && f._taxName != null) f.getItem('ten_thue%l').value = f._taxName;}

      &ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d07')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
    v.set_currencyFields('t_tn_ct_nt, t_tien_gt_nt, t_tn_tt_nt, t_thue_nt : t_tn_ct, t_tien_gt, t_tn_tt, t_thue');
    v.addGridFields(g, 'tn_ct_nt, tien_gt_nt, tn_tt_nt, thue_nt : tn_ct, tien_gt, tn_tt, thue');
    v.addTotalFields(g, [['t_tn_ct_nt', 'tn_ct_nt'], ['t_tien_gt_nt', 'tien_gt_nt'], ['t_tn_tt_nt', 'tn_tt_nt'], ['t_thue_nt', 'thue_nt'], ['t_tn_ct', 'tn_ct'], ['t_tien_gt', 'tien_gt'], ['t_tn_tt', 'tn_tt'], ['t_thue', 'thue']]);
    v.set_referenceFields(null);
    v.set_executeExpression(['[t_tn_ct_nt]:=[t_tn_ct_nt]', '[t_tien_gt_nt]:=[t_tien_gt_nt]', '[t_tn_tt_nt]:=[t_tn_tt_nt]', '[t_thue_nt]:=[t_thue_nt]', '[t_tn_ct]:=[t_tn_ct]', '[t_tien_gt]:=[t_tien_gt]', '[t_tn_tt]:=[t_tn_tt]', '[t_thue]:=[t_thue]']);
&CurrencyDateChanged;
  onCurrencySelected: function(sender, e) {
    if (e.object._baseCurrency == e.type) {
      e.object._form.focusWhenTabChanged([['d07', 'ma_tn']&ListTabChange;&PostTabChange;]);
      &PostCurrencySelected;
    }
  }
}

      /* <flatten type="Javascript"> */
function onChange$Voucher$VoucherDate(o) {o.parentForm.getItem('ngay_ct').value = o.parentForm.getItem('ngay_lct').value;}
function onChange$Voucher$PatternCode(o) {o.parentForm.request('PatternCode', 'PatternCode', ['ma_tn'], o);}
/* </flatten> */
function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result, g = f.getItem("d07")._controlBehavior;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;

      &VoucherNumberReading;
      &CurrencyResponse;
      &ListResponseTicket;

    case 'PatternCode':
      f._baseCurrencyAmount = result[0].Value;
      f._foreignCurrencyAmount = result[1].Value;
      f.setItemValue('ma_thue', result[2].Value);
      f.setItemControlBehavior('ten_thue%l', result[3].Value, null, false);
      f.setItemValue('thue_suat', result[4].Value);
      validPatternCode(f);
      break;
    default:
      break;
  }
}
function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged(['d07'&ListTabChange;&PostTabChange;]);
  &PostTabFocus;
}
/* <flatten type="Javascript"> */
function validPatternCode(f){
  var g = f.getItem("d07")._controlBehavior, v = (f.getItemValue('ma_nt') == f._baseCurrency);
  var t1 = g._getColumnOrder('tn_tt_nt'), t2 = g._getColumnOrder('tn_tt'), t3 = g._getColumnOrder('tinh_thue_yn');
  var l0 = g._getColumnOrder('tien_gt'), l1 = g._getColumnOrder('tien_gt_nt'), l2 = g._getColumnOrder('stt_rec_nv');
  for (var i = 1; i <= g._rowCount; i++) {
    if (g._getItem(i, l2).label != null && g._getItem(i, l2).label.checked) {
      if (g._getItemValue(i, l0) == 0) g._setItemValue(i, l0, f._baseCurrencyAmount);
      if (g._getItemValue(i, l1) == 0) g._setItemValue(i, l1, v ? f._baseCurrencyAmount : f._foreignCurrencyAmount);
    }
    var o = g._getItem(i, 1);
    o.row = i;
    g.executeExpression(o, [g.$a.tn_tt_nt, g.$a.tn_tt, g.$a.thue_nt, g.$a.thue]);
  }
  g.executeAggregate([g.$a.t_tien_gt_nt, g.$a.t_tien_gt, g.$a.t_tn_tt_nt, g.$a.t_tn_tt, g.$a.t_thue_nt, g.$a.t_thue]);
}
/* </flatten> */
      &ListScript;
      &PostScript;

