if exists (select ma_thue from tdmthuetp where ma_thue = (select ma_thue_tp from tdmtn where ma_tn = @ma_tn))
	select a.nguong_thue as tien_gt, a.nguong_thue_nt as tien_gt_nt, b.ma_thue as ma_thue, b.ten_thue%l as ten_thue, b.thue_suat as thue_suat
	  from dbo.tdmtn a left join dbo.tdmthuetp b on a.ma_thue_tp = b.ma_thue
	  where a.ma_tn = @ma_tn and a.ma_thue_tp in (select ma_thue from dbo.tdmthuetp)
else
	select 0 as tien_gt, 0 as tien_gt_nt, null as ma_thue, null as ten_thue, 0 as thue_suat
return




